import{_ as e,o as a,c as r,a2 as o}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"OpenCode — Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/opencode/benchmarks.md","filePath":"research/agents/opencode/benchmarks.md"}'),n={name:"research/agents/opencode/benchmarks.md"};function i(s,t,d,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="opencode-—-benchmarks" tabindex="-1">OpenCode — Benchmarks <a class="header-anchor" href="#opencode-—-benchmarks" aria-label="Permalink to &quot;OpenCode — Benchmarks&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>OpenCode is a relatively young project (early 2025) and has limited benchmark data compared to established agents. The primary benchmark reference is Terminal-Bench 2.0, which evaluates terminal-based coding agents.</p><h2 id="terminal-bench-2-0" tabindex="-1">Terminal-Bench 2.0 <a class="header-anchor" href="#terminal-bench-2-0" aria-label="Permalink to &quot;Terminal-Bench 2.0&quot;">​</a></h2><p>Terminal-Bench is a benchmark designed specifically for terminal-based AI coding agents, testing their ability to solve real-world software engineering tasks.</p><h3 id="opencode-results" tabindex="-1">OpenCode Results <a class="header-anchor" href="#opencode-results" aria-label="Permalink to &quot;OpenCode Results&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody><tr><td><strong>Rank</strong></td><td>#50</td></tr><tr><td><strong>Model</strong></td><td>Claude Opus 4.5</td></tr><tr><td><strong>Score</strong></td><td>51.7%</td></tr><tr><td><strong>Category</strong></td><td>Terminal agents</td></tr></tbody></table><h3 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p>Terminal-Bench 2.0 evaluates agents on a variety of coding tasks including:</p><ul><li>Bug fixing</li><li>Feature implementation</li><li>Code refactoring</li><li>Test writing</li><li>Configuration changes</li></ul><p>The 51.7% score places OpenCode in the middle tier of evaluated agents. This is expected for a project in early development that was still rapidly evolving.</p><h3 id="comparison-with-peers" tabindex="-1">Comparison with Peers <a class="header-anchor" href="#comparison-with-peers" aria-label="Permalink to &quot;Comparison with Peers&quot;">​</a></h3><p>For reference, here are approximate ranges of Terminal-Bench scores for similar agents (scores may vary by model and configuration):</p><table tabindex="0"><thead><tr><th>Agent</th><th>Approximate Score Range</th><th>Notes</th></tr></thead><tbody><tr><td>Claude Code</td><td>60-75%</td><td>Mature, well-tuned</td></tr><tr><td>Codex CLI</td><td>55-65%</td><td>OpenAI&#39;s agent</td></tr><tr><td>Aider</td><td>40-55%</td><td>Depends on model</td></tr><tr><td><strong>OpenCode</strong></td><td><strong>51.7%</strong></td><td><strong>Early development</strong></td></tr><tr><td>Cline</td><td>35-50%</td><td>IDE-based</td></tr></tbody></table><p><em>Note: Scores are approximate and depend on model choice, configuration, and benchmark version.</em></p><h2 id="swe-bench" tabindex="-1">SWE-Bench <a class="header-anchor" href="#swe-bench" aria-label="Permalink to &quot;SWE-Bench&quot;">​</a></h2><p>No public SWE-bench results are available for OpenCode as of the time of archival. The project was focused on usability and multi-provider support rather than benchmark optimization.</p><h2 id="performance-characteristics" tabindex="-1">Performance Characteristics <a class="header-anchor" href="#performance-characteristics" aria-label="Permalink to &quot;Performance Characteristics&quot;">​</a></h2><p>While not formal benchmarks, OpenCode has some notable performance characteristics from its Go implementation:</p><h3 id="startup-time" tabindex="-1">Startup Time <a class="header-anchor" href="#startup-time" aria-label="Permalink to &quot;Startup Time&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th>OpenCode (Go)</th><th>Typical Python Agent</th><th>Typical Node.js Agent</th></tr></thead><tbody><tr><td>Cold start</td><td>~50-100ms</td><td>1-5s</td><td>500ms-2s</td></tr><tr><td>Binary size</td><td>~30-50MB</td><td>N/A (needs runtime)</td><td>N/A (needs runtime)</td></tr></tbody></table><p>The single Go binary means no dependency resolution, virtual environment activation, or module loading at startup.</p><h3 id="memory-usage" tabindex="-1">Memory Usage <a class="header-anchor" href="#memory-usage" aria-label="Permalink to &quot;Memory Usage&quot;">​</a></h3><p>Go&#39;s garbage collector and static compilation typically result in lower memory usage than Python/Node.js agents:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Approximate</th></tr></thead><tbody><tr><td>Base memory</td><td>~20-50MB</td></tr><tr><td>Per-session overhead</td><td>~5-10MB</td></tr><tr><td>TUI rendering</td><td>~10-20MB</td></tr></tbody></table><h3 id="concurrency" tabindex="-1">Concurrency <a class="header-anchor" href="#concurrency" aria-label="Permalink to &quot;Concurrency&quot;">​</a></h3><p>Go&#39;s goroutine model is particularly well-suited for the agent pattern:</p><ul><li>Streaming responses use channels (near-zero overhead)</li><li>Permission blocking uses channel synchronization</li><li>Multiple sessions can run concurrently</li><li>LSP clients run in background goroutines</li><li>Title generation runs asynchronously</li></ul><h2 id="cost-efficiency" tabindex="-1">Cost Efficiency <a class="header-anchor" href="#cost-efficiency" aria-label="Permalink to &quot;Cost Efficiency&quot;">​</a></h2><p>OpenCode tracks costs per session and per model. Here are the pricing tiers for commonly used models:</p><h3 id="anthropic-models" tabindex="-1">Anthropic Models <a class="header-anchor" href="#anthropic-models" aria-label="Permalink to &quot;Anthropic Models&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Input ($/1M)</th><th>Output ($/1M)</th><th>Context Window</th></tr></thead><tbody><tr><td>Claude 3.7 Sonnet</td><td>$3.00</td><td>$15.00</td><td>200K</td></tr><tr><td>Claude 3.5 Haiku</td><td>$0.80</td><td>$4.00</td><td>200K</td></tr><tr><td>Claude 3 Opus</td><td>$15.00</td><td>$75.00</td><td>200K</td></tr></tbody></table><h3 id="openai-models" tabindex="-1">OpenAI Models <a class="header-anchor" href="#openai-models" aria-label="Permalink to &quot;OpenAI Models&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Input ($/1M)</th><th>Output ($/1M)</th><th>Context Window</th></tr></thead><tbody><tr><td>GPT-4.1</td><td>$2.00</td><td>$8.00</td><td>1M</td></tr><tr><td>GPT-4.1-mini</td><td>$0.40</td><td>$1.60</td><td>1M</td></tr><tr><td>o3-mini</td><td>$1.10</td><td>$4.40</td><td>200K</td></tr></tbody></table><h3 id="google-gemini" tabindex="-1">Google Gemini <a class="header-anchor" href="#google-gemini" aria-label="Permalink to &quot;Google Gemini&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Input ($/1M)</th><th>Output ($/1M)</th><th>Context Window</th></tr></thead><tbody><tr><td>Gemini 2.5 Pro</td><td>$1.25</td><td>$10.00</td><td>1M</td></tr><tr><td>Gemini 2.0 Flash</td><td>$0.10</td><td>$0.40</td><td>1M</td></tr></tbody></table><h3 id="free-tier-via-github-copilot" tabindex="-1">Free Tier via GitHub Copilot <a class="header-anchor" href="#free-tier-via-github-copilot" aria-label="Permalink to &quot;Free Tier via GitHub Copilot&quot;">​</a></h3><p>A unique OpenCode advantage: if users have a GitHub Copilot subscription, they can access multiple models (Claude, GPT, Gemini) at <strong>no additional cost</strong> through the Copilot provider.</p><h2 id="factors-affecting-benchmark-performance" tabindex="-1">Factors Affecting Benchmark Performance <a class="header-anchor" href="#factors-affecting-benchmark-performance" aria-label="Permalink to &quot;Factors Affecting Benchmark Performance&quot;">​</a></h2><p>Several factors explain OpenCode&#39;s current benchmark positioning:</p><h3 id="strengths" tabindex="-1">Strengths <a class="header-anchor" href="#strengths" aria-label="Permalink to &quot;Strengths&quot;">​</a></h3><ol><li><strong>Persistent shell</strong>: State preservation across commands</li><li><strong>LSP integration</strong>: Real-time diagnostics after edits</li><li><strong>Sub-agent delegation</strong>: Efficient search via agent tool</li><li><strong>Sourcegraph integration</strong>: Access to reference implementations</li><li><strong>Multi-provider support</strong>: Can use the best model for each task</li></ol><h3 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h3><ol><li><strong>Sequential tool execution</strong>: No parallel tool calls</li><li><strong>No turn limit</strong>: Can get stuck in long loops</li><li><strong>Basic error recovery</strong>: No sophisticated retry strategies</li><li><strong>No test verification</strong>: Doesn&#39;t automatically run tests after fixes</li><li><strong>Early development</strong>: Many features were still in progress when archived</li></ol><h3 id="areas-for-improvement" tabindex="-1">Areas for Improvement <a class="header-anchor" href="#areas-for-improvement" aria-label="Permalink to &quot;Areas for Improvement&quot;">​</a></h3><ol><li><strong>Parallel tool execution</strong>: Would significantly reduce latency for multi-tool responses</li><li><strong>Smarter context management</strong>: Client-side token counting could prevent context overflow errors</li><li><strong>Automated testing loops</strong>: Running tests after code changes to verify fixes</li><li><strong>Better command safety</strong>: The banned command list could be more comprehensive</li><li><strong>Retrieval augmentation</strong>: File indexing for more targeted context injection</li></ol><h2 id="benchmark-methodology-notes" tabindex="-1">Benchmark Methodology Notes <a class="header-anchor" href="#benchmark-methodology-notes" aria-label="Permalink to &quot;Benchmark Methodology Notes&quot;">​</a></h2><p>When evaluating OpenCode&#39;s benchmark scores, consider:</p><ol><li><strong>Model dependency</strong>: OpenCode&#39;s performance varies significantly by model. Claude Opus 4.5 at 51.7% may differ substantially from GPT-4.1 or Gemini 2.5.</li><li><strong>Configuration sensitivity</strong>: The tool set, system prompt, and auto-compact settings all affect performance.</li><li><strong>Early development</strong>: The project was in rapid development when benchmarked; later versions (and the Crush successor) may perform differently.</li><li><strong>Terminal-Bench specificity</strong>: Terminal-Bench tests terminal-specific interactions that may not reflect general coding ability.</li></ol>',49)])])}const u=e(n,[["render",i]]);export{p as __pageData,u as default};
